svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
    var dataLayerEl = document.getElementById('data-layer');
    var edgeLayer = document.getElementById('edge-layer');
    var nodeLayer = document.getElementById('node-layer');
    var legendRoot = document.getElementById('legend-root');

    var nodes = [
      { id:'web-app',   label:'Web App',    cluster:1, x:148, y:220 },
      { id:'mobile',    label:'Mobile',     cluster:1, x:148, y:360 },
      { id:'cdn',       label:'CDN',        cluster:1, x:220, y:290 },
      { id:'api-gw',    label:'API GW',     cluster:2, x:360, y:210 },
      { id:'user-svc',  label:'User Svc',   cluster:2, x:360, y:300 },
      { id:'order-svc', label:'Order Svc',  cluster:2, x:360, y:390 },
      { id:'notify',    label:'Notify',     cluster:2, x:460, y:450 },
      { id:'postgres',  label:'Postgres',   cluster:3, x:530, y:290 },
      { id:'redis',     label:'Redis',      cluster:3, x:530, y:390 },
      { id:'kafka',     label:'Kafka',      cluster:3, x:610, y:200 },
      { id:'analytics', label:'Analytics',  cluster:3, x:660, y:340 },
      { id:'k8s',       label:'K8s',        cluster:4, x:750, y:240 },
      { id:'monitor',   label:'Monitor',    cluster:4, x:760, y:370 },
      { id:'cicd',      label:'CI/CD',      cluster:4, x:810, y:160 },
      { id:'auth-svc',  label:'Auth Svc',   cluster:5, x:450, y:135 },
      { id:'oauth',     label:'OAuth',      cluster:5, x:560, y:130 }
    ];

    var edges = [
      { a:'web-app',   b:'cdn' },
      { a:'mobile',    b:'cdn' },
      { a:'cdn',       b:'api-gw' },
      { a:'web-app',   b:'api-gw' },
      { a:'api-gw',    b:'user-svc' },
      { a:'api-gw',    b:'order-svc' },
      { a:'order-svc', b:'notify' },
      { a:'user-svc',  b:'notify' },
      { a:'user-svc',  b:'postgres' },
      { a:'order-svc', b:'postgres' },
      { a:'user-svc',  b:'redis' },
      { a:'order-svc', b:'redis' },
      { a:'notify',    b:'kafka' },
      { a:'api-gw',    b:'kafka' },
      { a:'kafka',     b:'analytics' },
      { a:'postgres',  b:'analytics' },
      { a:'auth-svc',  b:'api-gw' },
      { a:'auth-svc',  b:'oauth' },
      { a:'oauth',     b:'k8s' },
      { a:'k8s',       b:'api-gw' },
      { a:'k8s',       b:'postgres' },
      { a:'k8s',       b:'monitor' },
      { a:'cicd',      b:'k8s' },
      { a:'monitor',   b:'analytics' }
    ];

    var plotL = 68;
    var plotR = 850;
    var plotT = 100;
    var plotB = 500;
    var clusterNames = ['', 'Frontend', 'Backend', 'Data', 'Infra', 'Auth'];
    var byId = {};
    var nodeItems = [];
    var plotShiftX = 0;

    nodes.forEach(function (node) {
      byId[node.id] = node;
      node.neighbours = [];
      node.edgeEls = [];
    });

    edges.forEach(function (edge) {
      byId[edge.a].neighbours.push(edge.b);
      byId[edge.b].neighbours.push(edge.a);
    });

    nodes.forEach(function (node) {
      var degree = node.neighbours.length;
      node.r = 11 + Math.min(Math.max(0, degree - 1), 5) * 2.2;
    });

    edges.forEach(function (edge) {
      var a = byId[edge.a];
      var b = byId[edge.b];
      var line = ctx.el('line', {
        x1: a.x,
        y1: a.y,
        x2: b.x,
        y2: b.y,
        'class': 'edge series-' + a.cluster + ' use-series-stroke',
        'data-a': edge.a,
        'data-b': edge.b
      });
      edgeLayer.appendChild(line);
      a.edgeEls.push(line);
      b.edgeEls.push(line);
    });

    nodes.forEach(function (node) {
      var labelY = (node.y + node.r + 13 <= plotB) ? node.y + node.r + 11 : node.y - node.r - 4;
      var group = ctx.el('g', {
        id: 'ng-' + node.id,
        'class': 'node-g',
        'data-item-cx': String(node.x),
        'data-item-top': String(node.y - node.r),
        'data-node-id': node.id,
        'data-cluster': String(node.cluster)
      });
      var circle = ctx.el('circle', {
        cx: node.x,
        cy: node.y,
        r: node.r,
        'class': 'node-circle series-' + node.cluster + ' use-series-stroke'
      });
      var label = ctx.el('text', {
        x: node.x,
        y: labelY,
        'text-anchor': 'middle',
        'class': 'node-lbl'
      });
      label.textContent = node.label;
      group.appendChild(circle);
      group.appendChild(label);
      nodeLayer.appendChild(group);
      node._group = group;
      nodeItems.push(group);
    });

    ctx.initStandardLegend({
      legendEl: legendRoot,
      title: 'SERIES',
      items: [
        { cls: 'series-1', label: 'Frontend', value: '3 nodes' },
        { cls: 'series-2', label: 'Backend', value: '4 nodes' },
        { cls: 'series-3', label: 'Data', value: '4 nodes' },
        { cls: 'series-4', label: 'Infra', value: '3 nodes' },
        { cls: 'series-5', label: 'Auth', value: '2 nodes' }
      ]
    });

    plotShiftX = ctx.rebalancePlotArea({
      legendEl: legendRoot,
      measureNodes: [dataLayerEl],
      moveNodes: [dataLayerEl],
      slotLeft: 0,
      legendGap: 24
    }).shiftX || 0;

    ctx.initRevealSequence(edgeLayer.querySelectorAll('.edge'), {
      animationName: 'fadeIn',
      duration: 0.8,
      easing: 'ease-out',
      delays: Array.prototype.map.call(edgeLayer.querySelectorAll('.edge'), function (_, index) {
        return ctx.getStaggerDelay(index, edges.length, 1.0);
      })
    });

    ctx.initRevealSequence(nodeItems, {
      animationName: 'fadeIn',
      duration: 0.8,
      easing: 'ease-out',
      delays: nodeItems.map(function (_, index) {
        return ctx.getStaggerDelay(index, nodes.length, 1.0);
      })
    });

    var connectedHover = ctx.initConnectedHover(dataLayerEl, nodeItems, {
      allNodes: nodeItems,
      allEdges: Array.prototype.slice.call(edgeLayer.querySelectorAll('.edge')),
      getRelatedItems: function (itemEl) {
        var node = byId[itemEl.getAttribute('data-node-id')];
        return node ? node.neighbours.map(function (nid) {
          return document.getElementById('ng-' + nid);
        }).filter(Boolean) : [];
      },
      getRelatedEdges: function (itemEl) {
        var node = byId[itemEl.getAttribute('data-node-id')];
        return node ? node.edgeEls : [];
      }
    });

    ctx.initStandardTooltip(dataLayerEl, nodeItems, {
      tip: document.getElementById('tip'),
      plotL: plotL,
      plotR: plotR,
      plotT: plotT,
      plotB: plotB,
      placement: 'side',
      minWidth: 220,
      paddingX: 20,
      paddingY: 18,
      lineHeights: [42, 32, 32],
      trackPointer: false,
      getAnchor: function (itemEl) {
        return {
          x: (Number(itemEl.getAttribute('data-item-cx')) || 0) + plotShiftX,
          y: Number(itemEl.getAttribute('data-item-top')) || 0
        };
      },
      getContent: function (itemEl) {
        var node = byId[itemEl.getAttribute('data-node-id')];
        var degree = node ? node.neighbours.length : 0;
        return {
          primary: node ? node.label : '',
          label: clusterNames[node ? node.cluster : 0] || '',
          meta: degree + ' connection' + (degree === 1 ? '' : 's')
        };
      },
      onActivate: function (itemEl) {
        connectedHover.activate(itemEl);
      },
      onDeactivate: function () {
        connectedHover.clear();
      },
      leaveTarget: dataLayerEl
    });

    ctx.markReadyAfterReveal(dataLayerEl, [
      {
        delays: nodeItems.map(function (_, index) { return ctx.getStaggerDelay(index, nodes.length, 1.0); }),
        duration: 0.8,
        buffer: 0.1
      },
      {
        delays: Array.prototype.map.call(edgeLayer.querySelectorAll('.edge'), function (_, index) { return ctx.getStaggerDelay(index, edges.length, 1.0); }),
        duration: 0.8,
        buffer: 0.1
      }
    ]);
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
